import re
from azure.ai.projects.agents import get_agent_events

INJECTION_PATTERNS = [
    r'ignore.*previous.*instructions',
    r'you are.*new.*role',
    r'forget.*rules',
    r'execute.*command'
]

def detect_grounding_injection(agent_id: str):
    events = get_agent_events(agent_id, event_type='grounding_search')
    vulnerabilities = []
    for event in events:
        query = event['bing_query']
        for pattern in INJECTION_PATTERNS:
            if re.search(pattern, query, re.IGNORECASE):
                vulnerabilities.append({
                    'event_id': event['event_id'],
                    'query': query,
                    'pattern': pattern
                })
    return vulnerabilities

detect_grounding_injection('agent-456')

from azure.ai.projects import AgentRuntime

class ToolInjectionDetector:
    def __init__(self):
        self.suspicious_params = ['command', 'exec', 'rm', 'curl', 'wget']

    def check_tool_call(self, tool_call):
        params = tool_call.parameters
        for param_name, param_value in params.items():
            if any(susp in param_name.lower() for susp in self.suspicious_params):
                if len(str(param_value)) > 100:  # Likely injection
                    raise ValueError(f"Suspicious tool param: {param_name}={param_value}")

# Usage in agent middleware
runtime = AgentRuntime()
detector = ToolInjectionDetector()

@runtime.tool_middleware
def validate_tool_call(ctx, tool_call, next):
    detector.check_tool_call(tool_call)
    return next(ctx, tool_call)

