from azure.ai.projects import AgentClient
from typing import Dict, Any

class SecureAgentClient(AgentClient):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.input_validator = InputValidator()

    def send_message(self, thread_id: str, content: str, **kwargs) -> Dict[str, Any]:
        # Validate input before sending
        validated_content = self.input_validator.sanitize(content)

        # Send as structured user message only
        return super().send_message(
            thread_id,
            content=validated_content,
            role='user',
            # System prompt remains isolated
            system_prompt=None
        )

class InputValidator:
    BLOCKLIST = ['ignore instructions', 'you are', 'forget rules']

    def sanitize(self, content: str) -> str:
        for pattern in self.BLOCKLIST:
            content = content.replace(pattern, '[REDACTED]')
        return content

client = SecureAgentClient.from_azure_project('secure-project')

from azure.ai.projects.agents import Agent
from azure.core.credentials import AzureKeyCredential

class SecureGroundingAgent(Agent):
    def create_grounding_query(self, user_query: str) -> str:
        # Parameterize instead of direct concatenation
        safe_query = self._parameterize_query(user_query)
        return f"enterprise search: {safe_query}"

    def _parameterize_query(self, query: str) -> str:
        # Remove dangerous characters and limit length
        safe_chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789 ' 
        sanitized = ''.join(c for c in query if c in safe_chars)[:200]
        return sanitized.strip()

    def search_with_grounding(self, question: str):
        safe_query = self.create_grounding_query(question)
        return self.bing_search(query=safe_query, grounding=True)

