from azure.ai.projects import AgentRuntime
from pydantic import BaseModel, validator
from typing import Any, Dict

class SafeToolParams(BaseModel):
    command: str = None
    path: str = None
    url: str = None

    @validator('command')
    def validate_command(cls, v):
        if v and any(x in v.lower() for x in ['rm', 'del', 'format', 'sudo']):
            raise ValueError('Dangerous command detected')
        return v

    @validator('path')
    def validate_path(cls, v):
        if v and '..' in v:
            raise ValueError('Path traversal detected')
        return v

@AgentRuntime.middleware()
def validate_tool_params(ctx, tool_call, next):
    try:
        SafeToolParams(**tool_call.parameters)
        return next(ctx, tool_call)
    except ValueError as e:
        # Log and block malicious call
        ctx.log_security_event('TOOL_INJECTION_BLOCKED', str(e))
        return {'error': 'Invalid tool parameters'}

runtime = AgentRuntime()
runtime.apply_middleware(validate_tool_params)

